-- Platform reference data imported from major_construction_fatality_incidents_2021_2026.xlsx.
-- Additive/idempotent: creates public reference tables and upserts the curated incident/control records.

create table if not exists public.platform_major_construction_fatality_incidents (
  incident_id text primary key,
  incident_name text not null,
  occurred_on date not null,
  incident_year integer not null,
  location text not null,
  state text not null,
  fatalities integer not null default 0,
  injuries text null,
  work_type text null,
  incident_type text null,
  osha_focus_four_exposures text[] not null default '{}'::text[],
  work_activity text null,
  immediate_cause text null,
  contributing_factors text null,
  missed_stop_work_trigger text null,
  preventive_controls text[] not null default '{}'::text[],
  platform_rule_trigger text null,
  tags text[] not null default '{}'::text[],
  source_level text null,
  confidence text null,
  source_urls text[] not null default '{}'::text[],
  source_workbook text not null default 'major_construction_fatality_incidents_2021_2026.xlsx',
  raw_payload jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.platform_major_construction_fatality_incident_controls (
  incident_id text not null references public.platform_major_construction_fatality_incidents(incident_id) on delete cascade,
  control_number integer not null,
  preventive_control text not null,
  related_permit_plan text null,
  severity_trigger text null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  primary key (incident_id, control_number)
);

create index if not exists platform_major_construction_fatality_incidents_year_idx
  on public.platform_major_construction_fatality_incidents(incident_year, occurred_on desc);
create index if not exists platform_major_construction_fatality_incidents_type_idx
  on public.platform_major_construction_fatality_incidents(incident_type);
create index if not exists platform_major_construction_fatality_incidents_tags_idx
  on public.platform_major_construction_fatality_incidents using gin(tags);
create index if not exists pmcfi_focus_four_idx
  on public.platform_major_construction_fatality_incidents using gin(osha_focus_four_exposures);

drop trigger if exists set_pmcfi_updated_at on public.platform_major_construction_fatality_incidents;
create trigger set_pmcfi_updated_at
before update on public.platform_major_construction_fatality_incidents
for each row execute function public.set_updated_at();

drop trigger if exists set_pmcfic_updated_at on public.platform_major_construction_fatality_incident_controls;
create trigger set_pmcfic_updated_at
before update on public.platform_major_construction_fatality_incident_controls
for each row execute function public.set_updated_at();

alter table public.platform_major_construction_fatality_incidents enable row level security;
alter table public.platform_major_construction_fatality_incident_controls enable row level security;

grant select on public.platform_major_construction_fatality_incidents to authenticated;
grant select on public.platform_major_construction_fatality_incident_controls to authenticated;
grant select, insert, update, delete on public.platform_major_construction_fatality_incidents to service_role;
grant select, insert, update, delete on public.platform_major_construction_fatality_incident_controls to service_role;

drop policy if exists pmcfi_select_all on public.platform_major_construction_fatality_incidents;
create policy pmcfi_select_all
on public.platform_major_construction_fatality_incidents for select to authenticated using (true);

drop policy if exists pmcfic_select_all on public.platform_major_construction_fatality_incident_controls;
create policy pmcfic_select_all
on public.platform_major_construction_fatality_incident_controls for select to authenticated using (true);

insert into public.platform_major_construction_fatality_incidents (
  incident_id,
  incident_name,
  occurred_on,
  incident_year,
  location,
  state,
  fatalities,
  injuries,
  work_type,
  incident_type,
  osha_focus_four_exposures,
  work_activity,
  immediate_cause,
  contributing_factors,
  missed_stop_work_trigger,
  preventive_controls,
  platform_rule_trigger,
  tags,
  source_level,
  confidence,
  source_urls,
  raw_payload
) values
  ('INC-001', 'Francis Scott Key Bridge Collapse', '2024-03-26', 2024, 'Baltimore, Maryland', 'Maryland', 6, '1 highway worker seriously injured; 1 inspector escaped unharmed', 'Highway maintenance / bridge work', 'Bridge collapse / vessel strike', array['Struck-by', 'caught-in/collapse', 'drowning/over-water exposure']::text[], 'Road maintenance work on bridge deck at night', 'Container ship Dali struck the bridge, causing structural collapse while workers were on deck.', 'External transportation interface; limited evacuation time; workers positioned on active infrastructure over water; night work exposure.', 'Emergency evacuation trigger for vessel/transportation threat; traffic/marine control alert; bridge impact risk.', array['Emergency communication plan', 'water rescue plan', 'night work accountability', 'real-time crew location', 'coordination with transportation authority/dispatch/harbor control.']::text[], 'RED: Bridge/roadway work over water with active transportation interface requires emergency evacuation and rescue plan.', array['bridge collapse', 'heavy civil', 'transportation interface', 'night work', 'over water', 'emergency response', 'catastrophic collapse', 'multi-fatality']::text[], 'NTSB investigation / public reporting', 'High', array['https://www.ntsb.gov/investigations/Pages/DCA24MM031.aspx', 'https://www.ntsb.gov/news/press-releases/Pages/NR20251118.aspx']::text[], '{"ID":"INC-001","Incident Name":"Francis Scott Key Bridge Collapse","Date":"2024-03-26","Year":"2024","Location":"Baltimore, Maryland","State":"Maryland","Fatalities":"6","Injuries":"1 highway worker seriously injured; 1 inspector escaped unharmed","Work Type":"Highway maintenance / bridge work","Incident Type":"Bridge collapse / vessel strike","OSHA Focus Four / Exposure":"Struck-by; caught-in/collapse; drowning/over-water exposure","Work Activity":"Road maintenance work on bridge deck at night","Immediate Cause":"Container ship Dali struck the bridge, causing structural collapse while workers were on deck.","Contributing Factors":"External transportation interface; limited evacuation time; workers positioned on active infrastructure over water; night work exposure.","Missed Stop-Work Trigger":"Emergency evacuation trigger for vessel/transportation threat; traffic/marine control alert; bridge impact risk.","Preventive Controls":"Emergency communication plan; water rescue plan; night work accountability; real-time crew location; coordination with transportation authority/dispatch/harbor control.","Platform Rule Trigger":"RED: Bridge/roadway work over water with active transportation interface requires emergency evacuation and rescue plan.","Tags":"bridge collapse; heavy civil; transportation interface; night work; over water; emergency response; catastrophic collapse; multi-fatality","Source Level":"NTSB investigation / public reporting","Confidence":"High","Source URLs":"https://www.ntsb.gov/investigations/Pages/DCA24MM031.aspx ; https://www.ntsb.gov/news/press-releases/Pages/NR20251118.aspx"}'::jsonb),
  ('INC-002', 'Boise Airport Hangar Collapse', '2024-01-31', 2024, 'Boise, Idaho', 'Idaho', 3, '8–9 injured; five critically reported', 'Aircraft hangar erection / steel erection', 'Structural steel / pre-engineered metal building collapse', array['Caught-in/collapse', 'struck-by', 'fall exposure']::text[], 'Aircraft hangar erection near Boise Airport', 'Partially erected hangar structure collapsed during construction.', 'Insufficient bracing/tensioned guy wires; visible instability signs reportedly ignored; bent or wavy I-beams; unbalanced columns; snapped wire rope cables.', 'Bent beams; leaning/unbalanced columns; snapped cables; frame movement; missing bracing or guying.', array['Engineered erection plan', 'daily bracing/guy wire verification', 'competent person signoff', 'wind/weather thresholds', 'hold point after instability warning.']::text[], 'RED: Steel/pre-engineered structure with missing bracing or visible movement requires immediate stop-work and engineered review.', array['steel erection', 'temporary bracing', 'structural collapse', 'hangar', 'airport construction', 'multi-fatality', 'stop-work trigger']::text[], 'OSHA investigation / AP', 'High', array['https://www.osha.gov/news/newsreleases/region10/07292024', 'https://apnews.com/article/c922f8ff2e4870f8a47a20f2372f4eb4']::text[], '{"ID":"INC-002","Incident Name":"Boise Airport Hangar Collapse","Date":"2024-01-31","Year":"2024","Location":"Boise, Idaho","State":"Idaho","Fatalities":"3","Injuries":"8–9 injured; five critically reported","Work Type":"Aircraft hangar erection / steel erection","Incident Type":"Structural steel / pre-engineered metal building collapse","OSHA Focus Four / Exposure":"Caught-in/collapse; struck-by; fall exposure","Work Activity":"Aircraft hangar erection near Boise Airport","Immediate Cause":"Partially erected hangar structure collapsed during construction.","Contributing Factors":"Insufficient bracing/tensioned guy wires; visible instability signs reportedly ignored; bent or wavy I-beams; unbalanced columns; snapped wire rope cables.","Missed Stop-Work Trigger":"Bent beams; leaning/unbalanced columns; snapped cables; frame movement; missing bracing or guying.","Preventive Controls":"Engineered erection plan; daily bracing/guy wire verification; competent person signoff; wind/weather thresholds; hold point after instability warning.","Platform Rule Trigger":"RED: Steel/pre-engineered structure with missing bracing or visible movement requires immediate stop-work and engineered review.","Tags":"steel erection; temporary bracing; structural collapse; hangar; airport construction; multi-fatality; stop-work trigger","Source Level":"OSHA investigation / AP","Confidence":"High","Source URLs":"https://www.osha.gov/news/newsreleases/region10/07292024 ; https://apnews.com/article/c922f8ff2e4870f8a47a20f2372f4eb4"}'::jsonb),
  ('INC-003', 'Port Arthur LNG Scaffolding / Climbing Formwork Failure', '2025-04-29', 2025, 'Port Arthur, Texas', 'Texas', 3, '2 injured', 'LNG industrial construction / tank work', 'Scaffold / climbing formwork failure', array['Falls', 'caught-in/collapse', 'struck-by']::text[], 'Tank work at elevation from climbing formwork system', 'Climbing formwork system workers were standing on gave way.', 'Elevated temporary work platform failure; critical system requiring independent inspection; high-energy fall exposure.', 'Formwork movement; missing inspection/tag; recently modified/jumped/loaded formwork; incomplete anchorage or manufacturer requirements.', array['Shift inspection', 'engineered design/manufacturer compliance', 'hold point after moving/jumping/modification', 'fall protection plan', 'elevated rescue plan.']::text[], 'RED: Climbing form/scaffold supporting workers requires documented inspection and hold point before access.', array['scaffold collapse', 'climbing formwork', 'LNG', 'tank work', 'work at height', 'industrial construction', 'multi-fatality']::text[], 'AP / company incident review', 'High', array['https://apnews.com/article/cd0251ae1b912e5254243b5ba6328225', 'https://www.bechtel.com/press-releases/port-arthur-lng-incident-what-weve-learned/']::text[], '{"ID":"INC-003","Incident Name":"Port Arthur LNG Scaffolding / Climbing Formwork Failure","Date":"2025-04-29","Year":"2025","Location":"Port Arthur, Texas","State":"Texas","Fatalities":"3","Injuries":"2 injured","Work Type":"LNG industrial construction / tank work","Incident Type":"Scaffold / climbing formwork failure","OSHA Focus Four / Exposure":"Falls; caught-in/collapse; struck-by","Work Activity":"Tank work at elevation from climbing formwork system","Immediate Cause":"Climbing formwork system workers were standing on gave way.","Contributing Factors":"Elevated temporary work platform failure; critical system requiring independent inspection; high-energy fall exposure.","Missed Stop-Work Trigger":"Formwork movement; missing inspection/tag; recently modified/jumped/loaded formwork; incomplete anchorage or manufacturer requirements.","Preventive Controls":"Shift inspection; engineered design/manufacturer compliance; hold point after moving/jumping/modification; fall protection plan; elevated rescue plan.","Platform Rule Trigger":"RED: Climbing form/scaffold supporting workers requires documented inspection and hold point before access.","Tags":"scaffold collapse; climbing formwork; LNG; tank work; work at height; industrial construction; multi-fatality","Source Level":"AP / company incident review","Confidence":"High","Source URLs":"https://apnews.com/article/cd0251ae1b912e5254243b5ba6328225 ; https://www.bechtel.com/press-releases/port-arthur-lng-incident-what-weve-learned/"}'::jsonb),
  ('INC-004', 'Charlotte Scaffolding Collapse', '2023-01-02', 2023, 'Charlotte, North Carolina', 'North Carolina', 3, '2 injured', 'Apartment construction / exterior work', 'Scaffold collapse / fall from elevation', array['Falls', 'caught-in/collapse', 'struck-by']::text[], 'Work from scaffolding on 16-story residential building site', 'Scaffold collapsed and workers reportedly fell about 70 feet.', 'Scaffold system failure; potential inspection/loading/erection issues; multi-employer responsibility exposure.', 'Uninspected or untagged scaffold; modification without reinspection; overload; weather impact; damaged components.', array['Green/yellow/red scaffold tagging', 'competent person inspection before shift and after changes/weather', 'load rating verification', 'user training', 'subcontractor responsibility assignment.']::text[], 'RED: Scaffold use after modification/weather or without documented competent-person inspection requires stop-work.', array['scaffold collapse', 'fall from elevation', 'multi-family construction', 'competent person', 'work platform', 'multi-fatality']::text[], 'AP / ENR / OSHA-related reporting', 'High', array['https://apnews.com/article/3359a7fb4cf532b9b3cf6effe0638d5d', 'https://www.enr.com/articles/56732-nc-penalizes-contractors-for-charlotte-scaffolding-collapse']::text[], '{"ID":"INC-004","Incident Name":"Charlotte Scaffolding Collapse","Date":"2023-01-02","Year":"2023","Location":"Charlotte, North Carolina","State":"North Carolina","Fatalities":"3","Injuries":"2 injured","Work Type":"Apartment construction / exterior work","Incident Type":"Scaffold collapse / fall from elevation","OSHA Focus Four / Exposure":"Falls; caught-in/collapse; struck-by","Work Activity":"Work from scaffolding on 16-story residential building site","Immediate Cause":"Scaffold collapsed and workers reportedly fell about 70 feet.","Contributing Factors":"Scaffold system failure; potential inspection/loading/erection issues; multi-employer responsibility expo