  ('INC-005', 'JFK Airport Trench / Concrete Slab Collapse', '2023-04-03', 2023, 'Queens, New York', 'New York', 2, 'No additional injuries listed in OSHA release', 'Water/sewer utility relocation / airport construction', 'Trench / excavation / concrete slab collapse', array['Caught-in/collapse', 'struck-by']::text[], 'Removing soil from beneath concrete slab during utility work', 'Concrete slab broke apart and collapsed while workers were removing soil beneath it.', 'Undermining unsupported slab; inadequate support/safe methods; excavation protective system design/supervision issues.', 'Working under/near slab, pavement, foundation, or wall without engineered support; undermining; changing soil/slab condition.', array['Excavation permit', 'engineered support plan', 'competent person inspection', 'protective system for qualifying excavations', 'safe access/egress.']::text[], 'RED: Soil removal beneath slab/pavement/foundation requires engineered support review and excavation permit.', array['trench collapse', 'concrete slab collapse', 'utility relocation', 'airport construction', 'caught-in', 'excavation permit', 'multi-fatality']::text[], 'OSHA investigation', 'High', array['https://www.osha.gov/news/newsreleases/new-york-city/20231016', 'https://www.dol.gov/newsroom/releases/osha/osha20231016']::text[], '{"ID":"INC-005","Incident Name":"JFK Airport Trench / Concrete Slab Collapse","Date":"2023-04-03","Year":"2023","Location":"Queens, New York","State":"New York","Fatalities":"2","Injuries":"No additional injuries listed in OSHA release","Work Type":"Water/sewer utility relocation / airport construction","Incident Type":"Trench / excavation / concrete slab collapse","OSHA Focus Four / Exposure":"Caught-in/collapse; struck-by","Work Activity":"Removing soil from beneath concrete slab during utility work","Immediate Cause":"Concrete slab broke apart and collapsed while workers were removing soil beneath it.","Contributing Factors":"Undermining unsupported slab; inade