  ('INC-006', 'Jarrell, Texas Trench Collapse', '2022-06-28', 2022, 'Jarrell, Texas', 'Texas', 2, 'Fatal collapse; no additional injuries highlighted', 'Sewer line installation', 'Deep trench collapse', array['Caught-in/collapse']::text[], 'Installing sewer lines in 23-foot-deep trench', 'Unprotected trench collapsed, crushing workers under soil and rock.', 'No trench protective system; 23-foot depth; lack of exit within 25 feet; temporary staffing exposure.', 'Trench 5 ft+ without protective system; deep trench without engineered system; no egress within 25 ft.', array['Trench box/shoring/sloping/benching', 'engineered protective system for deep excavations', 'egress within 25 ft', 'spoil setback', 'temporary worker verification.']::text[], 'RED: Any trench 5 ft+ without protective system or safe egress is a critical fatality condition.', array['trench collapse', 'sewer installation', 'deep excavation', 'temporary workers', 'caught-in', 'severe violator', 'multi-fatality']::text[], 'OSHA investigation', 'High', array['https://www.osha.gov/news/newsreleases/dallas/20221222']::text[], '{"ID":"INC-006","Incident Name":"Jarrell, Texas Trench Collapse","Date":"2022-06-28","Year":"2022","Location":"Jarrell, Texas","State":"Texas","Fatalities":"2","Injuries":"Fatal collapse; no additional injuries highlighted","Work Type":"Sewer line installation","Incident Type":"Deep trench collapse","OSHA Focus Four / Exposure":"Caught-in/collapse","Work Activity":"Installing sewer lines in 23-foot-deep trench","Immediate Cause":"Unprotected trench collapsed, crushing workers under soil and rock.","Contributing Factors":"No trench protective system; 23-foot depth; lack of exit within 25 feet; temporary staffing exposure.","Missed Stop-Work Trigger":"Trench 5 ft+ without protective system; deep trench without engineered system; no egress within 25 ft.","Preventive Controls":"Trench box/shoring/sloping/benching; engineered protective system for deep excavations; egress within 25 ft; spoil setback; temporary worker verification.","Platform Rule Trigger":"RED: Any trench 5 ft+ without protective system or safe egress is a critical fatality condition.","Tags":"trench collapse; sewer installation; deep excavation; temporary workers; caught-in; severe violator; multi-fatality","Source Level":"OSHA investigation","Confidence":"High","Source URLs":"https://www.osha.gov/news/newsreleases/dallas/20221222"}'::jsonb),
  ('INC-007', 'Boynton Beach Crane Collapse', '2022-03-22', 2022, 'Boynton Beach, Florida', 'Florida', 2, 'Not reported in cited source', 'Waterfront apartment construction', 'Crane collapse / concrete debris', array['Struck-by', 'caught/crushed-by']::text[], 'Crane reportedly supporting/handling a partition wall during construction', 'Crane collapsed and workers were found under concrete debris.', 'Possible suspended/supported load instability; workers in crush zone; lift planning/rigging/setup factors under investigation.', 'Workers under suspended/supported load; unclear load path; unstable wall/panel; crane setup uncertainty.', array['Critical lift plan', 'exclusion zone around suspended/supported loads', 'crane setup verification', 'lift director/rigger/signal person assignment', 'stop for unexpected load movement.']::text[], 'RED: Workers may not be inside fall/crush zone of suspended or crane-supported wall/panel/load.', array['crane collapse', 'critical lift', 'struck-by', 'crushed-by', 'concrete debris', 'exclusion zone', 'multi-fatality']::text[], 'Local reporting / OSHA investigation noted', 'Medium-High', array['https://cbs12.com/news/local/crane-collapse-kills-deadly-boynton-beach-construction-woolbright']::text[], '{"ID":"INC-007","Incident Name":"Boynton Beach Crane Collapse","Date":"2022-03-22","Year":"2022","Location":"Boynton Beach, Florida","State":"Florida","Fatalities":"2","Injuries":"Not reported in cited source","Work Type":"Waterfront apartment construction","Incident Type":"Crane collapse / concrete debris","OSHA Focus Four / Exposure":"Struck-by; caught/crushed-by","Work Activity":"Crane reportedly supporting/handling a partition wall during construction","Immediate Cause":"Crane collapsed and workers were found under concrete debris.","Contributing Factors":"Possible suspended/supported load instability; workers in crush zone; lift planning/rigging/setup factors under investigation.","Missed Stop-Work Trigger":"Workers under suspended/supp