  ('INC-008', 'Austin Trench Collapse After Prior Partial Collapse', '2021-10-23', 2021, 'Austin, Texas', 'Texas', 1, '1 seriously injured', 'Residential wastewater line installation', 'Trench collapse / repeat collapse', array['Caught-in/collapse', 'struck-by']::text[], 'Workers re-entered 13-foot unprotected trench after earlier partial collapse', 'Trench collapsed after workers were sent back into unprotected excavation.', 'Prior partial collapse ignored; no protective system; inspection failure; struck-by exposure from materials/equipment.', 'Any cave-in/partial collapse; sloughing; water intrusion; cracking; re-entry without redesign/reinspection.', array['Mandatory stop-work after any collapse', 'reinspection and documented corrective action', 'competent person authority', 'excavation rescue plan', 'supervisor accountability.']::text[], 'RED: Any prior trench collapse or sloughing locks out re-entry until competent-person and engineering review is complete.', array['trench collapse', 'repeat collapse', 'stop-work failure', 'willful violation', 'wastewater line', 'competent person', 'fatality']::text[], 'OSHA investigation', 'High', array['https://www.osha.gov/news/newsreleases/dallas/20220421']::text[], '{"ID":"INC-008","Incident Name":"Austin Trench Collapse After Prior Partial Collapse","Date":"2021-10-23","Year":"2021","Location":"Austin, Texas","State":"Texas","Fatalities":"1","Injuries":"1 seriously injured","Work Type":"Residential wastewater line installation","Incident Type":"Trench collapse / repeat collapse","OSHA Focus Four / Exposure":"Caught-in/collapse; struck-by","Work Activity":"Workers re-entered 13-foot unprotected trench after earlier partial collapse","Immediate Cause":"Trench collapsed after workers were sent back into unprotected excavation.","Contributing Factors":"Prior partial collapse ignored; no protective system; inspection failure; struck-by exposure from materials/equipment.","Missed Stop-Work Trigger":"Any cave-in/partial collaps