  ('INC-009', 'Catonsville Trench / Retaining Wall Collapse', '2025-02-28', 2025, 'Catonsville, Maryland', 'Maryland', 2, 'Not reported in cited AP source', 'Residential renovation / retaining wall reinforcement', 'Trench collapse / retaining wall failure', array['Caught-in/collapse', 'crushed-by']::text[], 'Reinforcing a wall inside/adjacent to trench during home renovation', 'Retaining wall failed and trench collapsed, trapping workers.', 'Adjacent wall instability; residential excavation; possible inadequate wall support/shoring; rescue complexity.', 'Wall movement/cracking/bulging; excavation near retaining wall without support review; workers below unsupported structure.', array['Excavation/wall support review', 'protective system', 'competent person inspection of adjacent structures', 'rescue plan', 'stop-work for wall movement.']::text[], 'RED: Excavation near retaining wall or foundation requires structural support review before worker entry.', array['trench collapse', 'retaining wall', 'residential renovation', 'caught-in', 'small contractor', 'multi-fatality']::text[], 'AP / local reporting', 'High', array['https://apnews.com/article/construction-workers-killed-trench-collapse-maryland-602341bb0ff2bec59de16d7a395c7f15', 'https://www.wbaltv.com/article/rescue-call-academy-road-catonsville/63976067']::text[], '{"ID":"INC-009","Incident Name":"Catonsville Trench / Retaining Wall Collapse","Date":"2025-02-28","Year":"2025","Location":"Catonsville, Maryland","State":"Maryland","Fatalities":"2","Injuries":"Not reported in cited AP source","Work Type":"Residential renovation / retaining wall reinforcement","Incident Type":"Trench collapse / retaining wall failure","OSHA Focus Four / Exposure":"Caught-in/collapse; crushed-by","Work Activity":"Reinforcing a wall inside/adjacent to trench during home renovation","Immediate Cause":"Retaining wall failed and trench collapsed, trapping workers.","Contributing Factors":"Adjacent wall instability; residential excavation;